#if swift(>=5.8)
@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterOptionSequenceString: FfiConverterRustBuffer {
    typealias SwiftType = [String]?

    public static func write(_ value: SwiftType, into buf: inout [UInt8]) {
        guard let value = value else {
            writeInt(&buf, Int8(0))
            return
        }
        writeInt(&buf, Int8(1))
        FfiConverterSequenceString.write(value, into: &buf)
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SwiftType {
        switch try readInt(&buf) as Int8 {
        case 0: return nil
        case 1: return try FfiConverterSequenceString.read(from: &buf)
        default: throw UniffiInternalError.unexpectedOptionalTag
        }
    }
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterSequenceString: FfiConverterRustBuffer {
    typealias SwiftType = [String]

    public static func write(_ value: [String], into buf: inout [UInt8]) {
        let len = Int32(value.count)
        writeInt(&buf, len)
        for item in value {
            FfiConverterString.write(item, into: &buf)
        }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> [String] {
        let len: Int32 = try readInt(&buf)
        var seq = [String]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterString.read(from: &buf))
        }
        return seq
    }
}

private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 30
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_brook_md_ffi_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_brook_md_ffi_checksum_method_brooksession_all_blocks() != 46557) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_brook_md_ffi_checksum_method_brooksession_append() != 15626) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_brook_md_ffi_checksum_method_brooksession_buffer_len() != 7914) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_brook_md_ffi_checksum_method_brooksession_finalize() != 60540) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_brook_md_ffi_checksum_method_brooksession_reset() != 39920) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_brook_md_ffi_checksum_method_brooksession_retained_bytes() != 8193) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_brook_md_ffi_checksum_constructor_brooksession_new() != 2220) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_brook_md_ffi_checksum_constructor_brooksession_new_with_config() != 3151) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

// Make the ensure init function public so that other modules which have external type references to
// our types can call it.
public func uniffiEnsureBrookMdFfiInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

